  });
};

export const validateToken = async (token: string, baseUrl: string): Promise<boolean> => {
  // Simulate an API validation check
  return new Promise((resolve) => {
    setTimeout(() => {
      // Logic: Token must start with 'sk_' to be valid for this demo
      resolve(token.startsWith('sk_') && baseUrl.length > 0);
    }, 1000);
  });
};

