import React, { useState, useEffect } from 'react';
import { Card, Input, Button, Badge } from '../components/UI';
import { getApiConfig, saveApiConfig, validateToken } from '../services/api';

const Settings = () => {
  const [activeTab, setActiveTab] = useState('api');
  const [apiConfig, setApiConfig] = useState({ baseUrl: '', token: '', secretKey: '' });
  const [isSaving, setIsSaving] = useState(false);
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');

  useEffect(() => {
    const config = getApiConfig();
    setApiConfig({
      baseUrl: config.baseUrl || '',
      token: config.token || '',
      secretKey: config.secretKey || ''
    });
  }, []);

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    setStatus('idle');

    try {
      const isValid = await validateToken(apiConfig.token, apiConfig.baseUrl);
      if (isValid) {
        saveApiConfig(apiConfig);
        setStatus('success');
      } else {
        setStatus('error');
      }
    } catch (error) {
      setStatus('error');
    } finally {
      setIsSaving(false);
    }
  };

  const tabs = [
    { id: 'api', label: 'API Configuration' },
    { id: 'departments', label: 'Departments' },
    { id: 'roles', label: 'Roles & Permissions' },
    { id: 'notifications', label: 'Notifications' },
  ];

  return (
    <div className="p-8 max-w-6xl mx-auto space-y-6">
      <div className="flex flex-col gap-2">
        <h1 className="text-3xl font-bold text-text">Settings</h1>
        <p className="text-textMuted">Manage your system preferences and integrations.</p>
      </div>

      <div className="flex items-center gap-4 border-b border-border">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`pb-3 px-1 text-sm font-medium transition-all relative ${
              activeTab === tab.id ? 'text-primary' : 'text-textMuted hover:text-text'
            }`}
          >
            {tab.label}
            {activeTab === tab.id && (
              <span className="absolute bottom-0 left-0 w-full h-0.5 bg-primary rounded-t-full"></span>
            )}
          </button>
        ))}
      </div>

      {activeTab === 'api' && (
        <Card className="max-w-2xl p-6">
          <form onSubmit={handleSave} className="space-y-6">
            <div>
              <h2 className="text-lg font-semibold text-text mb-1">API Connection</h2>
              <p className="text-sm text-textMuted">Configure the connection to the Nexus Backend Server.</p>
            </div>

            <div className="space-y-4">
              <Input
                label="API Base URL"
                placeholder="https://api.nexus-hrm.com/v1"
                value={apiConfig.baseUrl}
                onChange={(e) => setApiConfig({ ...apiConfig, baseUrl: e.target.value })}
                required
              />
              <Input
                label="API Token (JWT)"
                type="password"
                placeholder="sk_live_..."
                value={apiConfig.token}
                onChange={(e) => setApiConfig({ ...apiConfig, token: e.target.value })}
                required
              />
              <Input
                label="Secret Key (Optional)"
                type="password"
                placeholder="For HMAC signing"
                value={apiConfig.secretKey}
                onChange={(e) => setApiConfig({ ...apiConfig, secretKey: e.target.value })}
              />
            </div>

            <div className="bg-surfaceHighlight p-4 rounded-lg border border-border text-sm">
              <h4 className="font-medium text-text mb-2">Security Note</h4>
              <p className="text-textMuted">
                Your API token is stored locally in your browser. All requests to the backend will automatically include this token in the <code className="text-accent">Authorization</code> header.
              </p>
            </div>

            <div className="flex items-center justify-between pt-4">
               <div className="flex items-center gap-2">
                 {status === 'success' && <Badge variant="success">Connected Successfully</Badge>}
                 {status === 'error' && <Badge variant="danger">Connection Failed</Badge>}
               </div>
              <Button type="submit" disabled={isSaving}>
                {isSaving ? 'Validating...' : 'Save & Test Connection'}
              </Button>
            </div>
          </form>
        </Card>
      )}

      {activeTab === 'departments' && (
        <Card className="p-12 text-center text-textMuted">
           <h3 className="text-lg font-medium text-text">Department Management</h3>
           <p>This module allows CRUD operations for organizational structure.</p>
           {/* Placeholder for brevity of the demo */}
        </Card>
      )}
    </div>
  );
};

export default Settings;

import React, { useEffect, useState } from 'react';
import { Card, Button, Input, Badge } from '../components/UI';
import { IconSearch, IconUsers } from '../components/Icons';
import { fetchEmployees } from '../services/api';
import { Employee } from '../types';

const Employees = () => {
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    fetchEmployees().then(data => {
      setEmployees(data);
      setLoading(false);
    });
  }, []);

  const filteredEmployees = employees.filter(emp => 
    emp.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    emp.department.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-3xl font-bold text-text">Employees</h1>
           <p className="text-textMuted">Manage your workforce profile and details.</p>
        </div>
        <div className="flex gap-3">
           <Button variant="secondary">Import CSV</Button>
           <Button>+ Add Employee</Button>
        </div>
      </div>

      <Card className="overflow-hidden">
        {/* Toolbar */}
        <div className="p-4 border-b border-border flex items-center gap-4">
           <div className="relative w-full max-w-sm">
              <IconSearch className="absolute left-3 top-2.5 w-4 h-4 text-textMuted" />
              <input 
                type="text" 
                placeholder="Search by name, id or department..." 
                className="w-full bg-surfaceHighlight border border-border rounded-lg py-2 pl-9 pr-4 text-sm text-text focus:outline-none focus:ring-2 focus:ring-primary"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
           </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-textMuted">
            <thead className="bg-surfaceHighlight text-xs uppercase font-medium text-text">
              <tr>
                <th className="px-6 py-4">Employee</th>
                <th className="px-6 py-4">ID</th>
                <th className="px-6 py-4">Designation</th>
                <th className="px-6 py-4">Department</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {loading ? (
                 <tr>
                    <td colSpan={6} className="px-6 py-8 text-center">
                       <div className="animate-pulse flex justify-center text-primary">Loading data...</div>
                    </td>
                 </tr>
              ) : filteredEmployees.length === 0 ? (
                 <tr>
                   <td colSpan={6} className="px-6 py-12 text-center text-textMuted">
                     No employees found matching your search.
                   </td>
                 </tr>
              ) : (
                filteredEmployees.map((emp) => (
                  <tr key={emp.id} className="hover:bg-surfaceHighlight/50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                         <div className="w-8 h-8 rounded-full bg-primary/20 text-primary flex items-center justify-center font-bold text-xs">
                           {emp.name.split(' ').map(n => n[0]).join('')}
