// Generic fetch wrapper with token injection
const apiFetch = async (endpoint: string) => {
  const config = getApiConfig();
  if (!config.token) throw new Error("Missing API Token");

  const baseUrl = config.baseUrl.replace(/\/$/, ''); // Remove trailing slash
  const separator = endpoint.includes('?') ? '&' : '?';
  const url = `${baseUrl}${endpoint}${separator}api_token=${config.token}`;

  const response = await fetch(url, {
    method: 'GET',
    headers: { 'Accept': 'application/json' }
  });

  if (!response.ok) {
    throw new Error(`API Request Failed: ${response.status} ${response.statusText}`);
  }
  return response.json();
};

export const fetchEmployees = async (): Promise<Employee[]> => {
  // The TIPSOI API doesn't list a direct "Get All People" endpoint in the provided doc pages
  // so we stick to mock data for the employee list for now.
  return new Promise((resolve) => {
    setTimeout(() => resolve(generateMockEmployees()), 600);
  });
};

export const fetchDevices = async (): Promise<Device[]> => {
  try {
    const config = getApiConfig();
    if (!config.token) return generateMockDevices();

    // Call: GET {{BASE URL}}/devices?api_token={{API TOKEN}}
    const data = await apiFetch('/devices');

    if (Array.isArray(data)) {
      return data;
    }
    return generateMockDevices();
  } catch (error) {
    console.warn("Failed to fetch devices from API, using mock.", error);
    return generateMockDevices();
  }
};

export const fetchAttendance = async (startDate?: string, endDate?: string): Promise<AttendanceRecord[]> => {
  try {
    const config = getApiConfig();
    if (!config.token) return generateMockAttendance();

    // Default dates if not provided: Current Month
    const now = new Date();
    const start = startDate || new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    const end = endDate || now.toISOString().split('T')[0];

    // Call: GET {{BASE URL}}/attendance_logs?api_token={{API TOKEN}}&start=...&end=...
    const endpoint = `/attendance_logs?start=${start}&end=${end}`;
    const response: AttendanceApiResponse = await apiFetch(endpoint);

    // Transform complex API structure to flat AttendanceRecord array
    const records: AttendanceRecord[] = [];

    if (response && response.attendances && Array.isArray(response.attendances.data)) {
      response.attendances.data.forEach(person => {
        if (person.logs) {
          Object.keys(person.logs).forEach(dateKey => {
            const log = person.logs[dateKey];

            // Format times (extract HH:MM:SS from YYYY-MM-DD HH:MM:SS)
            const formatTime = (dateTimeStr: string) => {
              if (!dateTimeStr) return '-';
              return dateTimeStr.split(' ')[1] || dateTimeStr;
            };

            records.push({
              id: `${person.person_id}-${dateKey}`,
              employeeName: person.name,
              employeeId: person.person_identifier,
              date: dateKey,
              checkIn: formatTime(log.start),
              checkOut: formatTime(log.end),
              status: log.start ? 'Present' : 'Absent',
              location: 'Device Sync', // Location not in this specific response
              hours: log.hours
            });
          });
        }
      });
    }

    // Sort by date descending
    return records.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  } catch (error) {
    console.error("Failed to fetch attendance:", error);
    return generateMockAttendance();
  }
};

export const validateToken = async (token: string, baseUrl: string): Promise<boolean> => {
  try {
    const cleanBaseUrl = baseUrl.replace(/\/$/, '');
    // Using GET /devices as a lightweight check
    const url = `${cleanBaseUrl}/devices?api_token=${token}`;
    const response = await fetch(url);
    return response.ok;
  } catch (error) {
    return false;
  }
};

